INSERT INTO reading_passages (id, user_id, is_system, is_public, title, content, translation, jlpt_level, category, difficulty, word_count, tenant_id, is_active, is_deleted, created_at, created_by) VALUES (81105001, NULL, TRUE, TRUE, '初めての失敗 — プロセスシート 1', 'これは 初めての失敗 の プロセスシート です。Sonkeigo/Kenjougo + 4 cấp xin lỗi + trace lot + 5W1H + 5 Why に関する内容を含みます。実習生が業務中に必要な情報をまとめています。詳細は工場のマニュアルを参照してください。', 'Đây là Bảng quy trình của T5. Lần đầu mắc lỗi. Bao gồm nội dung liên quan đến Sonkeigo/Kenjougo + 4 cấp xin lỗi + trace lot + 5W1H + 5 Why. Tổng hợp thông tin thực tập sinh cần biết khi làm việc. Chi tiết xem sổ tay nhà máy.', 'N4', 'notice', 2, 150, 'system', TRUE, FALSE, NOW(), 'system') ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title, content = EXCLUDED.content, translation = EXCLUDED.translation, jlpt_level = EXCLUDED.jlpt_level, category = EXCLUDED.category, difficulty = EXCLUDED.difficulty, word_count = EXCLUDED.word_count, is_active = EXCLUDED.is_active, is_deleted = EXCLUDED.is_deleted, updated_at = NOW(), updated_by = 'system';
